import Link from "next/link";
import { usePathname } from "next/navigation";
import { Home, Wrench, MessageSquare, Sparkles } from "lucide-react";
import { useState } from "react";
import QuotationPopup from "./QuotationPopup";

const BottomNav = () => {
  const pathname = usePathname();
  const [isContactOpen, setIsContactOpen] = useState(false);

  const handleWhatsAppClick = () => {
    const message = "Hi! I'm interested in interior design services from EverySpaces. Please share more details.";
    const whatsappUrl = `https://wa.me/919886579923?text=${encodeURIComponent(message)}`;
    window.open(whatsappUrl, "_blank");
  };

  const navItems = [
    { icon: Home, label: "Home", href: "/" },
    { icon: Wrench, label: "Service", href: "/services" },
    { icon: null, label: "WhatsApp", action: handleWhatsAppClick },
    { icon: MessageSquare, label: "Contact", action: () => setIsContactOpen(true) },
    { icon: Sparkles, label: "Orza AI", href: "/orza-ai" },
  ];

  return (
    <>
      <nav className="fixed bottom-0 left-0 right-0 z-50 md:hidden">
        <div className="bg-primary shadow-[0_-4px_20px_rgba(0,0,0,0.15)] rounded-t-3xl px-2 py-2 safe-area-inset-bottom">
          <div className="flex items-center justify-around">
            {navItems.map((item, index) => {
              // Center WhatsApp button
              if (index === 2) {
                return (
                  <button
                    key={index}
                    onClick={item.action}
                    className="relative -mt-8 flex items-center justify-center"
                    aria-label="Contact us on WhatsApp"
                  >
                    <div className="w-16 h-16 rounded-full bg-secondary flex items-center justify-center shadow-glow animate-pulse-soft">
                      {/* WhatsApp Icon */}
                      <svg
                        viewBox="0 0 24 24"
                        fill="currentColor"
                        className="w-8 h-8 text-secondary-foreground"
                        aria-hidden="true"
                      >
                        <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z" />
                      </svg>
                    </div>
                  </button>
                );
              }

              const Icon = item.icon!;
              const isActive = item.href ? pathname === item.href : false;

              // Handle items with action (like Contact)
              if (item.action && !item.href) {
                return (
                  <button
                    key={index}
                    onClick={item.action}
                    className="flex flex-col items-center gap-1 py-2 px-3 transition-colors text-primary-foreground/70 hover:text-primary-foreground"
                  >
                    <Icon className="w-5 h-5" />
                    <span className="text-[10px] font-medium">{item.label}</span>
                  </button>
                );
              }

              return (
                <Link
                  key={index}
                  href={item.href!}
                  className={`flex flex-col items-center gap-1 py-2 px-3 transition-colors ${
                    isActive ? "text-secondary" : "text-primary-foreground/70 hover:text-primary-foreground"
                  }`}
                >
                  <Icon className="w-5 h-5" />
                  <span className="text-[10px] font-medium">{item.label}</span>
                </Link>
              );
            })}
          </div>
        </div>
      </nav>

      {/* Reuse the same QuotationPopup design */}
      <QuotationPopup 
        externalOpen={isContactOpen} 
        onExternalOpenChange={setIsContactOpen} 
      />
    </>
  );
};

export default BottomNav;
